+        const TEN_SEC = 10
+        const THIRTY_SEC = 30
+        const SIXTY_SEC = 60
+
+        // Show progressive messages so the user sees activity
+        let message: string
+        if (i === 0) {
+          message = 'Waiting for services to restart...'
+        } else if (elapsed < TEN_SEC) {
